+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {level: number, text: string};
+
+const tocStartMarker = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const tocEndMarker = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^ {0,3}(#{1,6})(?:[ \	]+|$)(.*)$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.HEADING,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lineEnding = text.includes('\\r\
') ? '\\r\
' : '\
';
+    const lines = text.split(/\\r?\
/);
+    const startIndex = lines.findIndex((line) => tocStartMarker.test(line));
+    if (startIndex === -1) {
+      return text;
+    }
+
+    const endOffset = lines.slice(startIndex + 1).findIndex((line) => tocEndMarker.test(line));
+    const endIndex = endOffset === -1 ? -1 : startIndex + 1 + endOffset;
+    const headings = getHeadings(lines, startIndex, endIndex, options)
+        .filter((heading) => heading.level >= options.minLevel && heading.level <= options.maxLevel)
+        .filter((heading) => !isExcluded(heading.text, options.excludeHeadings));
+    const tocLines = buildToc(lines[startIndex], headings, options);
+
+    if (endIndex === -1) {
+      lines.splice(startIndex, 1, ...tocLines);
+    } else {
+      lines.splice(startIndex, endIndex - startIndex + 1, ...tocLines);
+    }
+    return lines.join(lineEnding);
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [new ExampleBuilder({
+      description: 'Generates a table of contents where a TOC marker is present',
+      before: '<!-- toc -->\
\
## First section\
\
### Second section',
+      after: '<!-- toc -->\
\
- [First section](#first-section)\
  - [Second section](#second-section)\
\
<!-- /toc -->\
\
## First section\
\
### Second section',
+    })];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.list-style.name', descriptionKey: 'rules.auto-toc.list-style.description', optionsKey: 'listStyle', records: [
+        {value: 'bullet', description: 'Bullet list'}, {value: 'number', description: 'Numbered list'},
+      ]}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.bullet-marker.name', descriptionKey: 'rules.auto-toc.bullet-marker.description', optionsKey: 'bulletMarker'}),
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.ordered-list-style.name', descriptionKey: 'rules.auto-toc.ordered-list-style.description', optionsKey: 'orderedListStyle', records: [
+        {value: 'always-one', description: 'Always use 1.'}, {value: 'increment', description: 'Increment'},
+      ]}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.indent-size.name', descriptionKey: 'rules.auto-toc.indent-size.description', optionsKey: 'indentSize'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.min-level.name', descriptionKey: 'rules.auto-toc.min-level.description', optionsKey: 'minLevel'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.max-level.name', descriptionKey: 'rules.auto-toc.max-level.description', optionsKey: 'maxLevel'}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.title.name', descriptionKey: 'rules.auto-toc.title.description', optionsKey: 'title'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.strip-formatting-in-toc.name', descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description', optionsKey: 'stripFormattingInToc'}),
+      new TextAreaOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.exclude-headings.name', descriptionKey: 'rules.auto-toc.exclude-headings.description', optionsKey: 'excludeHeadings'}),
+    ];
+  }
+}
+
+function getHeadings(lines: string[], tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+  const headings: Heading[] = [];
+  let inYaml = lines[0]?.trim() === '---';
+  let inCodeFence = false;
+  let inMathBlock = false;
+
+  for (let index = 0; index < lines.length; index++) {
+    const line = lines[index];
+    if (inYaml) {
+      if (index > 0 && /^(---|\\.\\.\\.)\\s*$/.test(line)) inYaml = false;
+      continue;
+    }
+    if (/^\\s*(`{3,}|~{3,})/.test(line)) {
+      inCodeFence = !inCodeFence;
+      continue;
+    }
+    if (inCodeFence) continue;
+    if (/^\\s*\\$\\$\\s*$/.test(line)) {
+      inMathBlock = !inMathBlock;
+      continue;
+    }
+    if (inMathBlock || (index > tocStart && (tocEnd === -1 || index < tocEnd))) continue;
+
+    const match = line.match(atxHeading);
+    if (match) headings.push({level: match[1].length, text: match[2]});
+  }
+  return headings;
+}
+
+function buildToc(startMarker: string, headings: Heading[], options: AutoTocOptions): string[] {
+  const anchors = new Map<string, number>();
+  const items = headings.map((heading, index) => {
+    const display = headingDisplayText(heading.text, options.useExplicitIds);
+    const baseAnchor = explicitId(heading.text, options.useExplicitIds) ?? toAnchor(display);
+    const count = anchors.get(baseAnchor) ?? 0;
+    anchors.set(baseAnchor, count + 1);
+    const anchor = count === 0 ? baseAnchor : `${baseAnchor}-${count}`;
+    const marker = options.listStyle === 'number' ? (options.orderedListStyle === 'increment' ? `${index + 1}.` : '1.') : options.bulletMarker;
+    const text = options.stripFormattingInToc ? stripFormatting(display) : display;
+    return `${' '.repeat(Math.max(0, options.indentSize * (heading.level - options.minLevel)))}${marker} [${text}](#${anchor})`;
+  });
+  const result = [startMarker, ''];
+  if (options.title) result.push(options.title, '');
+  result.push(...items, '', '<!-- /toc -->', '');
+  return result;
+}
+
+function headingDisplayText(text: string, useExplicitIds: boolean): string {
+  const withoutId = useExplicitIds ? text.replace(/\\s*\\{#[^}\\s]+\\}\\s*$/, '') : text;
+  return withoutId.replace(/\\s+#+\\s*$/, '').trim();
+}
+
+function explicitId(text: string, useExplicitIds: boolean): string | undefined {
+  if (!useExplicitIds) return undefined;
+  return text.match(/\\s*\\{#([^}\\s]+)\\}\\s*$/)?.[1];
+}
+
+function toAnchor(text: string): string {
+  return stripFormatting(resolveLinks(text))
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9-_]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-|-$/g, '');
+}
+
+function resolveLinks(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)\\|([^\\]]+)\\]\\]/g, '$2')
+      .replace(/\\[\\[([^\\]]+)\\]\\]/g, '$1')
+      .replace(/\\[([^\\]]+)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return text.replace(/(\\*\\*|__|~~|\\*|_|`)/g, '').replace(/\\\\(.)/g, '$1');
+}
+
+function isExcluded(text: string, exclusions: string[]): boolean {
+  const heading = headingDisplayText(text, false);
+  return exclusions.some((exclusion) => {
+    const regex = exclusion.match(/^\\/(.*)\\/$/);
+    if (regex) {
+      try {
+        return new RegExp(regex[1], 'i').test(heading);
+      } catch (_) {
+        return heading.toLowerCase() === exclusion.toLowerCase();
+      }
+    }
+    return heading.toLowerCase() === exclusion.toLowerCase();
+  });
+}
